const items = $input.all();
return items.map(item => {
  const url = item.json.resume 
           || item.json.Resume 
           || item.json['Upload Resume']
           || item.json.resume_url 
           || '';

  let file_id = null;
  if (url && typeof url === 'string') {
    // Handles all Google Drive URL formats
    const match = url.match(/\/d\/([a-zA-Z0-9_-]+)/)
                || url.match(/id=([a-zA-Z0-9_-]+)/)
                || url.match(/open\?id=([a-zA-Z0-9_-]+)/);
    file_id = match ? match[1] : null;
  }

  return {
    json: {
      ...item.json,
      file_id
    }
  };
});

const results = [];

for (const item of $input.all()) {
  const response = item.json;

  if (!response.choices || !response.choices[0]) {
    results.push({ json: { error: 'No choices in response' } });
    continue;
  }

  const text = response.choices[0].message.content;
  const start = text.indexOf('{');
  const end = text.lastIndexOf('}');

  if (start === -1 || end === -1) {
    results.push({ json: { error: 'No JSON found', raw: text } });
    continue;
  }

  const cleaned = text.substring(start, end + 1);

  let result;
  try {
    result = JSON.parse(cleaned);
  } catch(e) {
    results.push({ json: { error: 'Parse failed', raw: cleaned } });
    continue;
  }

  results.push({
    json: {
      email: $('Getting File ID').first().json['email-1'],
      name:$('Getting File ID').first().json['name-1'] ,
      role:$('Getting File ID').first().json.role ,
      classification: result.classification,
      score : result.score,
      summary: result.summary,
      strengths: result.strengths,
      concerns: result.concerns,
      interview_recommendation: result.interview_recommendation
    }
  });
}

return results;
